import base64
import json
import os
import subprocess
from google.cloud import storage

def convert_image(event, context):
    """
    Cloud Function that converts an image from Google Cloud Storage using ImageMagick.
    The function is triggered by a new object in a GCS bucket.
    Conversion options and output filename are extracted from the object's metadata.
    """

    bucket_name = event['bucket']
    input_blob_name = event['name']
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    input_blob = bucket.object(input_blob_name)

    # Get metadata from the input object
    metadata = input_blob.metadata
    if not metadata:
        print(f"No metadata found for {input_blob_name}. Skipping conversion.")
        return

    # Extract conversion options and output filename from metadata
    # Expected metadata keys: 'conversion_options', 'output_filename'
    conversion_options_str = metadata.get('conversion_options')
    output_filename = metadata.get('output_filename')

    if not conversion_options_str or not output_filename:
        print(f"Missing 'conversion_options' or 'output_filename' in metadata for {input_blob_name}. Skipping conversion.")
        return

    # Create a temporary directory for input and output files
    temp_dir = '/tmp'
    input_path = os.path.join(temp_dir, input_blob_name.split('/')[-1])
    output_path = os.path.join(temp_dir, output_filename)

    # Download the input image
    input_blob.download_to_filename(input_path)
    print(f"Downloaded {input_blob_name} to {input_path}")

    # Prepare ImageMagick command
    # conversion_options_str should be a space-separated string of ImageMagick options, e.g., "-resize 50% -quality 80"
    command = ['convert', input_path] + conversion_options_str.split() + [output_path]
    print(f"Running command: {' '.join(command)}")

    try:
        # Execute ImageMagick command
        subprocess.run(command, check=True, capture_output=True)
        print(f"Successfully converted {input_blob_name} to {output_filename}")

        # Upload the converted image back to the same bucket
        output_blob = bucket.blob(output_filename)
        output_blob.upload_from_filename(output_path)
        print(f"Uploaded {output_filename} to gs://{bucket_name}/{output_filename}")

    except subprocess.CalledProcessError as e:
        print(f"Error during ImageMagick conversion: {e}")
        print(f"STDOUT: {e.stdout.decode()}")
        print(f"STDERR: {e.stderr.decode()}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        # Clean up temporary files
        if os.path.exists(input_path):
            os.remove(input_path)
            print(f"Cleaned up {input_path}")
        if os.path.exists(output_path):
            os.remove(output_path)
            print(f"Cleaned up {output_path}")